#include<bits/stdc++.h>
using namespace std;
vector<pair<int,int>> mp[400010];
int dis[400010];
bool vis[400010];
void spfa()
{
    priority_queue<pair<int,int>> q;
    q.push(make_pair(0,1));
    memset(dis,0x3f,sizeof(dis));
    dis[1]=0;
    while(!q.empty())
    {
        int t=q.top().second;
        q.pop();
        vis[t]=1;
        for(pair<int,int> i:mp[t])
        {
            int v=i.first,val=i.second;
            if(!vis[v]&dis[v]>dis[t]+val)
            {
                dis[v]=dis[t]+val;
                q.push(make_pair(-dis[v],v));
            }
        }
    }
}
void add(int u,int v,int w)
{
    mp[u].push_back(make_pair(v,w));
    mp[v].push_back(make_pair(u,w));
}
int main()
{
    int n,m,k;
    scanf("%d%d%d",&n,&m,&k);
    for(int i=1;i<=m;i++)
    {
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        if(w==0)
        {
            add(u+n,v+n,1);
        }
        else
        {
            add(u,v,1);
        }
    }
    for(int i=1;i<=k;i++)
    {
        int x;
        scanf("%d",&x);
        add(x,x+n,0);
    }
    spfa();
    if(dis[n]==0x3f3f3f3f&&dis[n*2]==0x3f3f3f3f)
    {
        printf("-1");
        return 0;
    }
    printf("%d",min(dis[n],dis[n*2]));
    return 0;
}
